1	import { Prisma } from '../models/prisma';
2	import { getPrisma } from '../config/database';
3	import {
4	  AppError,
5	  NOT_FOUND,
6	  FORBIDDEN,
7	  CONFLICT,
8	  VALIDATION_ERROR,
9	} from '../utils/errors';
10	
11	/* ---------- Helpers ---------- */
12	
13	function timeToMinutes(time: string): number {
14	  const [h, m] = time.split(':').map(Number);
15	  return h * 60 + m;
16	}
17	
18	async function enforceOwnership(itineraryId: string, userId: string, role: string) {
19	  const prisma = getPrisma();
20	  const itinerary = await prisma.itinerary.findUnique({ where: { id: itineraryId } });
21	  if (!itinerary) throw new AppError(404, NOT_FOUND, 'Itinerary not found');
22	  if (role !== 'admin' && itinerary.ownerId !== userId) throw new AppError(403, FORBIDDEN, 'Access denied');
23	  return itinerary;
24	}
25	
26	/**
27	 * Itinerary metadata fields that participate in version snapshots and diffs.
28	 *
29	 * `status` is intentionally NOT in this list — status-only updates are routine
30	 * lifecycle transitions (draft → published → archived) and shouldn't burn a
31	 * new version. The "should we cut a new version?" decision in updateItinerary
32	 * only triggers on these content fields.
33	 */
34	const VERSIONED_METADATA_FIELDS = ['title', 'destination', 'startDate', 'endDate'] as const;
35	
36	interface ItineraryMetadataSnapshot {
37	  id: string;
38	  ownerId: string;
39	  title: string;
40	  destination: string | null;
41	  startDate: string | null;
42	  endDate: string | null;
43	  status: string;
44	}
45	
46	interface ItineraryItemSnapshot {
47	  id: string;
48	  resourceId: string;
49	  dayNumber: number;
50	  startTime: string;
51	  endTime: string;
52	  notes: string | null;
53	  position: number;
54	}
55	
56	interface ItinerarySnapshot {
57	  schemaVersion: number;
58	  metadata: ItineraryMetadataSnapshot;
59	  items: ItineraryItemSnapshot[];
60	}
61	
62	interface MetadataDiff {
63	  field: string;
64	  from: unknown;
65	  to: unknown;
66	}
67	
68	function isoOrNull(value: Date | string | null | undefined): string | null {
69	  if (!value) return null;
70	  if (value instanceof Date) return value.toISOString();
71	  return new Date(value).toISOString();
72	}
73	
74	function buildItemSnapshot(item: {
75	  id: string;
76	  resourceId: string;
77	  dayNumber: number;
78	  startTime: string;
79	  endTime: string;
80	  notes: string | null;
81	  position: number;
82	}): ItineraryItemSnapshot {
83	  return {
84	    id: item.id,
85	    resourceId: item.resourceId,
86	    dayNumber: item.dayNumber,
87	    startTime: item.startTime,
88	    endTime: item.endTime,
89	    notes: item.notes,
90	    position: item.position,
91	  };
92	}
93	
94	async function createVersion(itineraryId: string, userId: string) {
95	  const prisma = getPrisma();
96	
97	  // Capture both itinerary metadata AND items in the snapshot. Earlier the
98	  // snapshot was an items-only array, which meant a renamed itinerary or
99	  // shifted travel dates left no recoverable history.
100	  const itinerary = await prisma.itinerary.findUnique({
101	    where: { id: itineraryId },
102	  });
103	  if (!itinerary) throw new AppError(404, NOT_FOUND, 'Itinerary not found');
104	
105	  const items = await prisma.itineraryItem.findMany({
106	    where: { itineraryId },
107	    orderBy: [{ dayNumber: 'asc' }, { startTime: 'asc' }],
108	  });
109	
110	  const snapshot: ItinerarySnapshot = {
111	    schemaVersion: 2,
112	    metadata: {
113	      id: itinerary.id,
114	      ownerId: itinerary.ownerId,
115	      title: itinerary.title,
116	      destination: itinerary.destination ?? null,
117	      startDate: isoOrNull(itinerary.startDate),
118	      endDate: isoOrNull(itinerary.endDate),
119	      status: itinerary.status,
120	    },
121	    items: items.map(buildItemSnapshot),
122	  };
123	
124	  // Determine next version number
125	  const lastVersion = await prisma.itineraryVersion.findFirst({
126	    where: { itineraryId },
127	    orderBy: { versionNumber: 'desc' },
128	  });
129	  const nextNumber = lastVersion ? lastVersion.versionNumber + 1 : 1;
130	
131	  // Compute diff from previous version. Diff covers BOTH metadata and items
132	  // so consumers can render a full change log without diffing the snapshots
133	  // themselves.
134	  let diffMetadata: Record<string, unknown> | null = null;
135	  if (lastVersion) {
136	    const rawPrev = lastVersion.snapshot as unknown;
137	
138	    // Snapshots written before schemaVersion 2 were a bare items array. Wrap
139	    // legacy rows so the diff computation can treat them uniformly.
140	    let prev: ItinerarySnapshot;
141	    if (Array.isArray(rawPrev)) {
142	      prev = {
143	        schemaVersion: 1,
144	        metadata: snapshot.metadata, // unknown; assume no metadata change
145	        items: rawPrev as unknown as ItineraryItemSnapshot[],
146	      };
147	    } else {
148	      prev = rawPrev as ItinerarySnapshot;
149	    }
150	
151	    // Item-level diff
152	    const currentIds = new Set(items.map((i) => i.id));
153	    const prevItems = prev.items ?? [];
154	    const prevIds = new Set(prevItems.map((i) => i.id));
155	    const added = items.filter((i) => !prevIds.has(i.id)).map((i) => i.id);
156	    const removed = prevItems.filter((i) => !currentIds.has(i.id)).map((i) => i.id);
157	    const modified = items
158	      .filter((i) => prevIds.has(i.id))
159	      .filter((cur) => {
160	        const previous = prevItems.find((p) => p.id === cur.id);
161	        if (!previous) return false;
162	        return (
163	          previous.startTime !== cur.startTime ||
164	          previous.endTime !== cur.endTime ||
165	          previous.dayNumber !== cur.dayNumber ||
166	          previous.resourceId !== cur.resourceId ||
167	          previous.notes !== cur.notes ||
168	          previous.position !== cur.position
169	        );
170	      })
171	      .map((i) => i.id);
172	
173	    // Metadata-level diff. Only the versioned fields participate — status is
174	    // tracked in snapshot but not in the diff so a status-only PATCH is a no-op.
175	    const metadataChanges: MetadataDiff[] = [];
176	    if (prev.schemaVersion >= 2) {
177	      const prevMeta = prev.metadata as unknown as Record<string, unknown>;
178	      const curMeta = snapshot.metadata as unknown as Record<string, unknown>;
179	      for (const field of VERSIONED_METADATA_FIELDS) {
180	        const before = prevMeta[field];
181	        const after = curMeta[field];
182	        if (before !== after) {
183	          metadataChanges.push({ field, from: before ?? null, to: after ?? null });
184	        }
185	      }
186	    }
187	
188	    diffMetadata = {
189	      items: { added, removed, modified },
190	      metadata: metadataChanges,
191	    };
192	  }
193	
194	  return prisma.itineraryVersion.create({
195	    data: {
196	      itineraryId,
197	      versionNumber: nextNumber,
198	      snapshot: JSON.parse(JSON.stringify(snapshot)) as Prisma.InputJsonValue,
199	      diffMetadata: (diffMetadata as Prisma.InputJsonValue) ?? undefined,
200	      createdBy: userId,
201	    },
202	  });
203	}
204	
205	async function validateItem(
206	  itineraryId: string,
207	  dayNumber: number,
208	  startTime: string,
209	  endTime: string,
210	  resourceId: string,
211	  excludeItemId?: string,
212	) {
213	  const prisma = getPrisma();
214	  const startMin = timeToMinutes(startTime);
215	  const endMin = timeToMinutes(endTime);
216	
217	  if (startMin >= endMin) {
218	    throw new AppError(400, VALIDATION_ERROR, 'startTime must be before endTime');
219	  }
220	
221	  // Load resource with hours and closures
222	  const resource = await prisma.resource.findUnique({
223	    where: { id: resourceId },
224	    include: { hours: true, closures: true },
225	  });
226	  if (!resource) throw new AppError(404, NOT_FOUND, 'Resource not found');
227	
228	  // 1. Min dwell time check
229	  const durationMinutes = endMin - startMin;
230	  if (durationMinutes < resource.minDwellMinutes) {
231	    throw new AppError(
232	      400,
233	      VALIDATION_ERROR,
234	      `Duration (${durationMinutes}min) is less than minimum dwell time (${resource.minDwellMinutes}min)`,
235	    );
236	  }
237	
238	  // 2. Closure date check — need itinerary start date to compute actual date
239	  const itinerary = await prisma.itinerary.findUnique({ where: { id: itineraryId } });
240	  if (!itinerary) throw new AppError(404, NOT_FOUND, 'Itinerary not found');
241	
242	  if (itinerary.startDate) {
243	    const actualDate = new Date(itinerary.startDate);
244	    actualDate.setDate(actualDate.getDate() + (dayNumber - 1));
245	    // Normalize to date-only for comparison
246	    const dateStr = actualDate.toISOString().split('T')[0];
247	
248	    const closure = resource.closures.find((c) => {
249	      const closureStr = new Date(c.date).toISOString().split('T')[0];
250	      return closureStr === dateStr;
251	    });
252	    if (closure) {
253	      throw new AppError(
254	        400,
255	        VALIDATION_ERROR,
256	        `Resource is closed on this date${closure.reason ? ': ' + closure.reason : ''}`,
257	      );
258	    }
259	
260	    // 3. Business hours check
261	    const dayOfWeek = actualDate.getDay();
262	    const hoursForDay = resource.hours.filter((h) => h.dayOfWeek === dayOfWeek);
263	    if (hoursForDay.length > 0) {
264	      const withinAnyWindow = hoursForDay.some((h) => {
265	        const openMin = timeToMinutes(h.openTime);
266	        const closeMin = timeToMinutes(h.closeTime);
267	        return startMin >= openMin && endMin <= closeMin;
268	      });
269	      if (!withinAnyWindow) {
270	        throw new AppError(400, VALIDATION_ERROR, 'Item time falls outside business hours');
271	      }
272	    }
273	  }
274	
275	  // 4. Load existing items on same day for overlap / buffer / travel checks
276	  const existingItems = await prisma.itineraryItem.findMany({
277	    where: {
278	      itineraryId,
279	      dayNumber,
280	      ...(excludeItemId ? { id: { not: excludeItemId } } : {}),
281	    },
282	    include: { resource: true },
283	    orderBy: { startTime: 'asc' },
284	  });
285	
286	  const BUFFER_MINUTES = 15;
287	
288	  for (const item of existingItems) {
289	    const existStart = timeToMinutes(item.startTime);
290	    const existEnd = timeToMinutes(item.endTime);
291	
292	    // 5. Overlap detection
293	    if (startMin < existEnd && endMin > existStart) {
294	      throw new AppError(409, CONFLICT, 'Time slot overlaps with an existing item');
295	    }
296	
297	    // 6. 15-minute buffer
298	    if (
299	      (startMin >= existEnd && startMin < existEnd + BUFFER_MINUTES) ||
300	      (endMin > existStart - BUFFER_MINUTES && endMin <= existStart)
301	    ) {
302	      throw new AppError(409, CONFLICT, 'Items must have at least a 15-minute buffer between them');
303	    }
304	  }
305	
306	  // 7. Travel time from previous item
307	  // Find the item that ends right before our start
308	  const previousItem = existingItems
309	    .filter((i) => timeToMinutes(i.endTime) <= startMin)
310	    .sort((a, b) => timeToMinutes(b.endTime) - timeToMinutes(a.endTime))[0];
311	
312	  if (previousItem) {
313	    const travelTime = await prisma.travelTimeMatrix.findFirst({
314	      where: {
315	        fromResourceId: previousItem.resourceId,
316	        toResourceId: resourceId,
317	      },
318	    });
319	
320	    if (travelTime) {
321	      const prevEnd = timeToMinutes(previousItem.endTime);
322	      const gap = startMin - prevEnd;
323	      if (gap < travelTime.travelMinutes) {
324	        throw new AppError(
325	          409,
326	          CONFLICT,
327	          `Insufficient travel time from previous item (need ${travelTime.travelMinutes}min, have ${gap}min)`,
328	        );
329	      }
330	    }
331	  }
332	}
333	
334	/* ---------- Itinerary CRUD ---------- */
335	
336	export async function createItinerary(
337	  ownerId: string,
338	  data: { title: string; destination?: string; startDate?: string | Date; endDate?: string | Date },
339	) {
340	  const prisma = getPrisma();
341	  const itinerary = await prisma.itinerary.create({
342	    data: {
343	      ownerId,
344	      title: data.title,
345	      destination: data.destination,
346	      startDate: data.startDate ? new Date(data.startDate) : undefined,
347	      endDate: data.endDate ? new Date(data.endDate) : undefined,
348	    },
349	  });
350	  // Initial save = version 1. Captures the empty-items snapshot at creation
351	  // time so the version history is well-defined from the very first read.
352	  await createVersion(itinerary.id, ownerId);
353	  return itinerary;
354	}
355	
356	export async function listItineraries(
357	  userId: string,
358	  role: string,
359	  filters: { status?: string; page?: number; limit?: number },
360	) {
361	  const prisma = getPrisma();
362	  const page = filters.page ?? 1;
363	  const limit = filters.limit ?? 20;
364	  const skip = (page - 1) * limit;
365	
366	  const where: Record<string, unknown> = {};
367	  if (role !== 'admin') {
368	    where.ownerId = userId;
369	  }
370	  if (filters.status) where.status = filters.status;
371	
372	  const [data, total] = await Promise.all([
373	    prisma.itinerary.findMany({ where, skip, take: limit, orderBy: { updatedAt: 'desc' } }),
374	    prisma.itinerary.count({ where }),
375	  ]);
376	
377	  return { data, total, page, limit };
378	}
379	
380	export async function getItinerary(id: string, userId: string, role: string) {
381	  const prisma = getPrisma();
382	  const itinerary = await prisma.itinerary.findUnique({
383	    where: { id },
384	    include: {
385	      items: {
386	        include: { resource: true },
387	        orderBy: [{ dayNumber: 'asc' }, { startTime: 'asc' }],
388	      },
389	    },
390	  });
391	  if (!itinerary) throw new AppError(404, NOT_FOUND, 'Itinerary not found');
392	  if (role !== 'admin' && itinerary.ownerId !== userId) {
393	    throw new AppError(403, FORBIDDEN, 'Access denied');
394	  }
395	  return itinerary;
396	}
397	
398	export async function updateItinerary(
399	  id: string,
400	  userId: string,
401	  role: string,
402	  data: Record<string, unknown>,
403	) {
404	  const itinerary = await enforceOwnership(id, userId, role);
405	  const prisma = getPrisma();
406	
407	  // Determine if this is a content change (not just status)
408	  const contentFields = ['title', 'destination', 'startDate', 'endDate'];
409	  const isContentChange = contentFields.some((f) => f in data);
410	
411	  // Normalize date fields
412	  const updateData: Record<string, unknown> = { ...data };
413	  if (updateData.startDate) updateData.startDate = new Date(updateData.startDate as string);
414	  if (updateData.endDate) updateData.endDate = new Date(updateData.endDate as string);
415	
416	  const updated = await prisma.itinerary.update({ where: { id }, data: updateData });
417	
418	  if (isContentChange) {
419	    await createVersion(id, userId);
420	  }
421	
422	  return updated;
423	}
424	
425	export async function deleteItinerary(id: string, userId: string, role: string) {
426	  await enforceOwnership(id, userId, role);
427	  const prisma = getPrisma();
428	  await prisma.itinerary.delete({ where: { id } });
429	}
430	
431	/* ---------- Itinerary Items ---------- */
432	
433	export async function addItem(
434	  itineraryId: string,
435	  userId: string,
436	  role: string,
437	  data: {
438	    resourceId: string;
439	    dayNumber: number;
440	    startTime: string;
441	    endTime: string;
442	    notes?: string;
443	    position?: number;
444	  },
445	) {
446	  await enforceOwnership(itineraryId, userId, role);
447	
448	  await validateItem(itineraryId, data.dayNumber, data.startTime, data.endTime, data.resourceId);
449	
450	  const prisma = getPrisma();
451	  const item = await prisma.itineraryItem.create({
452	    data: {
453	      itineraryId,
454	      resourceId: data.resourceId,
455	      dayNumber: data.dayNumber,
456	      startTime: data.startTime,
457	      endTime: data.endTime,
458	      notes: data.notes,
459	      position: data.position ?? 0,
460	    },
461	    include: { resource: true },
462	  });
463	
464	  await createVersion(itineraryId, userId);
465	  return item;
466	}
467	
468	export async function updateItem(
469	  itineraryId: string,
470	  itemId: string,
471	  userId: string,
472	  role: string,
473	  data: {
474	    resourceId?: string;
475	    dayNumber?: number;
476	    startTime?: string;
477	    endTime?: string;
478	    notes?: string;
479	    position?: number;
480	  },
481	) {
482	  await enforceOwnership(itineraryId, userId, role);
483	
484	  const prisma = getPrisma();
485	  const existing = await prisma.itineraryItem.findFirst({
486	    where: { id: itemId, itineraryId },
487	  });
488	  if (!existing) throw new AppError(404, NOT_FOUND, 'Itinerary item not found');
489	
490	  const merged = {
491	    resourceId: data.resourceId ?? existing.resourceId,
492	    dayNumber: data.dayNumber ?? existing.dayNumber,
493	    startTime: data.startTime ?? existing.startTime,
494	    endTime: data.endTime ?? existing.endTime,
495	  };
496	
497	  await validateItem(
498	    itineraryId,
499	    merged.dayNumber,
500	    merged.startTime,
501	    merged.endTime,
502	    merged.resourceId,
503	    itemId,
504	  );
505	
506	  const updated = await prisma.itineraryItem.update({
507	    where: { id: itemId },
508	    data: {
509	      resourceId: merged.resourceId,
510	      dayNumber: merged.dayNumber,
511	      startTime: merged.startTime,
512	      endTime: merged.endTime,
513	      notes: data.notes !== undefined ? data.notes : undefined,
514	      position: data.position !== undefined ? data.position : undefined,
515	    },
516	    include: { resource: true },
517	  });
518	
519	  await createVersion(itineraryId, userId);
520	  return updated;
521	}
522	
523	export async function removeItem(
524	  itineraryId: string,
525	  itemId: string,
526	  userId: string,
527	  role: string,
528	) {
529	  await enforceOwnership(itineraryId, userId, role);
530	
531	  const prisma = getPrisma();
532	  const existing = await prisma.itineraryItem.findFirst({
533	    where: { id: itemId, itineraryId },
534	  });
535	  if (!existing) throw new AppError(404, NOT_FOUND, 'Itinerary item not found');
536	
537	  await prisma.itineraryItem.delete({ where: { id: itemId } });
538	  await createVersion(itineraryId, userId);
539	}
540	
541	export async function listItems(
542	  itineraryId: string,
543	  userId: string,
544	  role: string,
545	  dayNumber?: number,
546	) {
547	  await enforceOwnership(itineraryId, userId, role);
548	
549	  const prisma = getPrisma();
550	  const where: Record<string, unknown> = { itineraryId };
551	  if (dayNumber !== undefined) where.dayNumber = dayNumber;
552	
553	  return prisma.itineraryItem.findMany({
554	    where,
555	    include: { resource: true },
556	    orderBy: [{ dayNumber: 'asc' }, { startTime: 'asc' }],
557	  });
558	}
559	
560	/* ---------- Versions ---------- */
561	
562	export async function getVersions(itineraryId: string, userId: string, role: string) {
563	  await enforceOwnership(itineraryId, userId, role);
564	
565	  const prisma = getPrisma();
566	  return prisma.itineraryVersion.findMany({
567	    where: { itineraryId },
568	    orderBy: { versionNumber: 'desc' },
569	  });
570	}
