1	import { Prisma } from '../models/prisma';
2	import { getPrisma } from '../config/database';
3	import {
4	  AppError,
5	  NOT_FOUND,
6	  VALIDATION_ERROR,
7	  CONFLICT,
8	} from '../utils/errors';
9	import crypto from 'crypto';
10	
11	/* ---------- Types ---------- */
12	
13	interface ModelConfig {
14	  rules?: ModelRule[];
15	  features?: string[];
16	  [key: string]: unknown;
17	}
18	
19	interface ModelRule {
20	  name: string;
21	  condition: string; // e.g. "input.budget < 100"
22	  output: { prediction: unknown; confidence: number };
23	}
24	
25	interface InferenceResult {
26	  prediction: unknown;
27	  confidence: number;
28	  confidenceBand: [number, number];
29	  topFeatures: { feature: string; contribution: number }[];
30	  appliedRules: { rule: string; triggered: boolean }[];
31	}
32	
33	/* ---------- Helpers ---------- */
34	
35	const VALID_SEMVER = /^\d+\.\d+\.\d+$/;
36	const VALID_TYPES = ['pmml', 'onnx', 'custom'];
37	const VALID_STATUSES = ['inactive', 'active', 'canary'];
38	
39	/**
40	 * Deterministic hash for A/B allocation routing.
41	 */
42	function allocationHash(userId: string, modelName: string): number {
43	  const hash = crypto.createHash('sha256').update(`${userId}:${modelName}`).digest();
44	  return hash.readUInt32BE(0) % 100;
45	}
46	
47	/* ---------- Model Adapter Interface ---------- */
48	
49	interface AdapterResult {
50	  prediction: unknown;
51	  confidence: number;
52	  topFeatures: { feature: string; contribution: number }[];
53	}
54	
55	export interface ModelAdapter {
56	  infer(input: Record<string, unknown>, config: ModelConfig | null): Promise<AdapterResult>;
57	}
58	
59	// In production, default to 'process' (fail-fast if binaries unavailable).
60	// In dev/test, default to 'mock' for safe deterministic behavior.
61	const ADAPTER_MODE = process.env.MODEL_ADAPTER_MODE
62	  || (process.env.NODE_ENV === 'production' ? 'process' : 'mock');
63	const PROCESS_TIMEOUT_MS = 30_000;
64	const ALLOWED_EXECUTABLES = ['/usr/bin/java', '/usr/bin/python3', '/usr/local/bin/python3'];
65	
66	function spawnAdapter(executable: string, args: string[], input: string): Promise<string> {
67	  return new Promise((resolve, reject) => {
68	    if (!ALLOWED_EXECUTABLES.some((e) => executable.startsWith(e))) {
69	      reject(new Error(`Executable not in allowlist: ${executable}`));
70	      return;
71	    }
72	    // eslint-disable-next-line @typescript-eslint/no-var-requires
73	    const { spawn } = require('child_process');
74	    const proc = spawn(executable, args, { timeout: PROCESS_TIMEOUT_MS });
75	    let stdout = '';
76	    let stderr = '';
77	    proc.stdin.write(input);
78	    proc.stdin.end();
79	    proc.stdout.on('data', (d: Buffer) => { stdout += d.toString(); });
80	    proc.stderr.on('data', (d: Buffer) => { stderr += d.toString(); });
81	    proc.on('close', (code: number) => {
82	      if (code !== 0) reject(new Error(`Process exited ${code}: ${stderr.slice(0, 500)}`));
83	      else resolve(stdout);
84	    });
