211	/**
212	 * Evaluate rules against input. Rules override model predictions when triggered.
213	 */
214	function evaluateRules(
215	  rules: ModelRule[],
216	  input: Record<string, unknown>,
217	): { appliedRules: { rule: string; triggered: boolean }[]; override: { prediction: unknown; confidence: number } | null } {
218	  const appliedRules: { rule: string; triggered: boolean }[] = [];
219	  let override: { prediction: unknown; confidence: number } | null = null;
220	
221	  for (const rule of rules) {
222	    const triggered = safeEvaluateCondition(rule.condition, input);
223	
224	    appliedRules.push({ rule: rule.name, triggered });
225	    if (triggered && !override) {
226	      override = { prediction: rule.output.prediction, confidence: rule.output.confidence };
227	    }
228	  }
229	
230	  return { appliedRules, override };
231	}
