336	export async function infer(
337	  modelId: string,
338	  input: Record<string, unknown>,
339	  context: Record<string, unknown>,
340	  userId?: string,
341	): Promise<InferenceResult> {
342	  const prisma = getPrisma();
343	
344	  let model = await prisma.mlModel.findUnique({
345	    where: { id: modelId },
346	    include: { abAllocations: true },
347	  });
348	  if (!model) throw new AppError(404, NOT_FOUND, 'Model not found');
349	
350	  // If model is canary or has canary allocations, check A/B routing
351	  if (userId && model.status === 'active') {
352	    // Look for a canary version of the same model name
353	    const canaryModel = await prisma.mlModel.findFirst({
354	      where: {
355	        name: model.name,
356	        status: 'canary',
357	      },
358	      include: { abAllocations: true },
359	    });
360	
361	    if (canaryModel && canaryModel.abAllocations.length > 0) {
362	      const hash = allocationHash(userId, model.name);
363	      const totalCanaryPercent = canaryModel.abAllocations.reduce(
364	        (sum, a) => sum + Number(a.percentage),
365	        0,
366	      );
367	      if (hash < totalCanaryPercent) {
368	        model = canaryModel;
369	      }
370	    }
371	  }
372	
373	  if (model.status !== 'active' && model.status !== 'canary') {
374	    throw new AppError(400, VALIDATION_ERROR, `Model is not active (status: ${model.status})`);
375	  }
376	
377	  const config = (model.config as ModelConfig) ?? null;
378	
379	  // Run inference via adapter (falls back to mock in dev/test)
380	  const adapter = getAdapter(model.type);
381	  const inferResult = await adapter.infer(input, config);
382	
383	  // Evaluate rules
384	  const rules = config?.rules ?? [];
385	  const { appliedRules, override } = evaluateRules(rules, input);
386	
387	  // Build confidence band
388	  const confidence = override ? override.confidence : inferResult.confidence;
389	  const bandWidth = (1 - confidence) * 0.5;
390	  const confidenceBand: [number, number] = [
391	    Math.round(Math.max(0, confidence - bandWidth) * 1000) / 1000,
392	    Math.round(Math.min(1, confidence + bandWidth) * 1000) / 1000,
393	  ];
394	
395	  return {
396	    prediction: override ? override.prediction : inferResult.prediction,
397	    confidence,
398	    confidenceBand,
399	    topFeatures: inferResult.topFeatures,
400	    appliedRules,
401	  };
402	}
