408	  if (!batch) throw new AppError(404, NOT_FOUND, 'Import batch not found');
409	  if (batch.userId !== userId) throw new AppError(403, FORBIDDEN, 'Access denied');
410	  if (batch.status === 'completed') throw new AppError(409, CONFLICT, 'Batch already committed');
411	  if (batch.status === 'rolled_back') throw new AppError(409, CONFLICT, 'Batch has been rolled back');
