427	
428	  if (batch.entityType === 'resources') {
429	    for (const row of validRows) {
430	      const data = row.data;
431	      const resource = await prisma.resource.create({
432	        data: {
433	          name: String(data.name),
434	          type: String(data.type).toLowerCase(),
435	          streetLine: data.streetLine ? String(data.streetLine) : null,
436	          city: data.city ? String(data.city) : null,
437	          region: data.region ? String(data.region) : null,
438	          country: data.country ? String(data.country) : null,
439	          latitude: data.latitude !== undefined && data.latitude !== null && data.latitude !== ''
440	            ? Number(data.latitude)
441	            : null,
442	          longitude: data.longitude !== undefined && data.longitude !== null && data.longitude !== ''
443	            ? Number(data.longitude)
444	            : null,
445	          minDwellMinutes: data.minDwellMinutes
446	            ? Number(data.minDwellMinutes)
