18	/* ---------- Sensitive Field Masking ---------- */
19	
20	const SENSITIVE_FIELDS = ['password_hash', 'passwordHash', 'answer_encrypted', 'answerEncrypted', 'tokenHash', 'token_hash'];
21	
22	function maskSensitiveFields(obj: unknown): unknown {
23	  if (obj === null || obj === undefined) return obj;
24	  if (typeof obj === 'string') return obj;
25	  if (Array.isArray(obj)) return obj.map(maskSensitiveFields);
26	  if (typeof obj === 'object') {
27	    const result: Record<string, unknown> = {};
28	    for (const [key, value] of Object.entries(obj as Record<string, unknown>)) {
29	      if (SENSITIVE_FIELDS.includes(key)) {
30	        result[key] = '[REDACTED]';
31	      } else if (typeof value === 'object' && value !== null) {
32	        result[key] = maskSensitiveFields(value);
33	      } else {
34	        result[key] = value;
35	      }
36	    }
37	    return result;
38	  }
39	  return obj;
40	}
41	
42	/* ---------- Build Where Clause ---------- */
43	
44	function buildWhereClause(filters: AuditFilters): Prisma.AuditLogWhereInput {
45	  const where: Prisma.AuditLogWhereInput = {};
46	  const andConditions: Prisma.AuditLogWhereInput[] = [];
47	
48	  if (filters.action) {
49	    where.action = filters.action;
50	  }
51	
52	  if (filters.from || filters.to) {
53	    const createdAt: Record<string, Date> = {};
54	    if (filters.from) createdAt.gte = new Date(filters.from);
55	    if (filters.to) createdAt.lte = new Date(filters.to);
56	    where.createdAt = createdAt;
57	  }
58	
59	  // actorId and resourceType are stored inside the detail JSON field
60	  if (filters.actorId) {
61	    andConditions.push({
62	      detail: {
63	        path: '$.actorId',
64	        equals: filters.actorId,
65	      },
66	    });
67	  }
68	
69	  if (filters.resourceType) {
70	    andConditions.push({
71	      detail: {
72	        path: '$.resourceType',
73	        equals: filters.resourceType,
74	      },
75	    });
76	  }
77	
78	  if (andConditions.length > 0) {
79	    where.AND = andConditions;
80	  }
81	
82	  return where;
83	}
