129	export function audit(
130	  req: Request,
131	  action: string,
132	  resourceType: string,
133	  resourceId: string,
134	  detail?: Record<string, unknown>,
135	): void {
136	  const actorId = req.user?.userId ?? 'anonymous';
137	  const requestId = getRequestId();
138	  // Fire-and-forget — failure to write an audit row must never block a
139	  // user-facing mutation, but we DO want it surfaced in the structured logs
140	  // so an alert can be wired off log volume.
141	  logAction(actorId, action, resourceType, resourceId, detail, requestId).catch((err) => {
142	    auditLogger.error('audit log write failed', {
