173	export async function exportAuditLogsCsv(filters: AuditFilters): Promise<string> {
174	  const prisma = getPrisma();
175	
176	  // For CSV export, fetch all matching records (no pagination)
177	  const where = buildWhereClause(filters);
178	
179	  const logs = await prisma.auditLog.findMany({
180	    where,
181	    orderBy: { createdAt: 'desc' },
182	  });
183	
184	  // CSV header
185	  const headers = ['id', 'action', 'actorId', 'resourceType', 'resourceId', 'detail', 'traceId', 'createdAt'];
186	  const rows: string[] = [headers.join(',')];
187	
188	  for (const log of logs) {
189	    const detail = (log.detail ?? {}) as Record<string, unknown>;
190	    const maskedDetail = maskSensitiveFields(detail) as Record<string, unknown>;
191	
192	    const actorId = maskedDetail.actorId ?? '';
193	    const resourceType = maskedDetail.resourceType ?? '';
194	    const resourceId = maskedDetail.resourceId ?? '';
195	
196	    // Remove actorId/resourceType/resourceId from detail for the detail column
197	    const extraDetail = { ...maskedDetail };
198	    delete extraDetail.actorId;
199	    delete extraDetail.resourceType;
200	    delete extraDetail.resourceId;
201	
202	    const detailStr = Object.keys(extraDetail).length > 0
203	      ? JSON.stringify(extraDetail)
204	      : '';
205	
206	    const row = [
207	      csvEscape(log.id),
208	      csvEscape(log.action),
209	      csvEscape(String(actorId)),
210	      csvEscape(String(resourceType)),
211	      csvEscape(String(resourceId)),
212	      csvEscape(detailStr),
213	      csvEscape(log.traceId ?? ''),
214	      csvEscape(log.createdAt.toISOString()),
215	    ];
216	
217	    rows.push(row.join(','));
218	  }
219	
220	  return rows.join('\n');
221	}
