223	/* ---------- CSV Utility ---------- */
224	
225	function csvEscape(value: string): string {
226	  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
227	    return `"${value.replace(/"/g, '""')}"`;
228	  }
229	  return value;
230	}
