1	/**
2	 * Contract sync tests.
3	 *
4	 * The TripForge API contract lives in two places:
5	 *   1. src/config/swagger.ts  — the live OpenAPI object served at /api/docs
6	 *   2. docs/api-spec.md       — the human-curated reference document
7	 *
8	 * The two MUST not drift. This suite parses both, normalises them, and asserts
9	 * that:
10	 *   - Every (path, method) pair documented in one exists in the other.
11	 *   - Endpoints that the audit historically flagged are now consistent:
12	 *       * POST /users is absent from both
13	 *       * GET /import/templates/:entityType is marked public in both
14	 *   - The shared error envelope schema lists `requestId` (the canonical field).
15	 *
16	 * The actual route table in src/routes/* must also match — that is exercised
17	 * by api_envelope.api.spec.ts which hits real routes.
18	 */
19	
20	import fs from 'fs';
21	import path from 'path';
22	import { apiSpec } from '../src/config/swagger';
23	
24	// js-yaml v3 — no @types installed but the API surface we need (`load`) is
25	// stable enough to type ad-hoc.
26	// eslint-disable-next-line @typescript-eslint/no-var-requires
27	const yaml = require('js-yaml') as { load(input: string): unknown; safeLoad?(input: string): unknown };
28	
29	interface OpenApiPaths {
30	  [path: string]: { [method: string]: unknown };
31	}
32	
33	function normalisePath(p: string): string {
34	  // Convert OpenAPI {id} -> :id so we can compare against express style if
35	  // ever needed; here we standardise on the {id} form for comparison.
36	  return p.replace(/\{(\w+)\}/g, '{$1}');
37	}
38	
39	function listOperations(spec: { paths: OpenApiPaths }): Set<string> {
40	  const ops = new Set<string>();
41	  for (const [p, methods] of Object.entries(spec.paths || {})) {
42	    for (const method of Object.keys(methods)) {
43	      if (['get', 'post', 'patch', 'put', 'delete'].includes(method.toLowerCase())) {
44	        ops.add(`${method.toUpperCase()} ${normalisePath(p)}`);
45	      }
46	    }
47	  }
48	  return ops;
49	}
50	
51	// Resolve the API spec from a self-contained location inside repo/ first.
52	// This lets reviewers run the test against repo/ alone (e.g. inside the
53	// Docker image, where the project-root `docs/` is not part of the build
54	// context). We fall back to `../../docs/api-spec.md` for backwards
55	// compatibility with checkouts where docs/ still lives at the project root.
56	const repoLocalDocs = path.resolve(__dirname, '..', 'docs', 'api-spec.md');
57	const projectRootDocs = path.resolve(__dirname, '..', '..', 'docs', 'api-spec.md');
58	const docsPath = fs.existsSync(repoLocalDocs) ? repoLocalDocs : projectRootDocs;
59	const docsYaml = fs.readFileSync(docsPath, 'utf8');
60	const loader = yaml.safeLoad ?? yaml.load;
61	const docsSpec = loader(docsYaml) as { paths: OpenApiPaths; components?: { schemas?: Record<string, unknown> } };
62	const swaggerSpec = apiSpec as { paths: OpenApiPaths; components?: { schemas?: Record<string, unknown> } };
63	
64	describe('API contract — swagger.ts vs docs/api-spec.md', () => {
65	  const swaggerOps = listOperations(swaggerSpec);
66	  const docsOps = listOperations(docsSpec);
67	
68	  it('docs/api-spec.md has paths defined', () => {
69	    expect(docsOps.size).toBeGreaterThan(0);
70	  });
71	
72	  it('swagger.ts has paths defined', () => {
73	    expect(swaggerOps.size).toBeGreaterThan(0);
74	  });
75	
76	  it('every operation in swagger.ts is also in docs/api-spec.md', () => {
77	    const missingFromDocs = [...swaggerOps].filter((op) => !docsOps.has(op));
78	    expect(missingFromDocs).toEqual([]);
79	  });
80	
81	  it('every operation in docs/api-spec.md is also in swagger.ts', () => {
82	    const missingFromSwagger = [...docsOps].filter((op) => !swaggerOps.has(op));
83	    expect(missingFromSwagger).toEqual([]);
84	  });
85	});
86	
87	describe('API contract — historical audit drift items', () => {
88	  it('POST /users is not present in either spec (use /auth/register)', () => {
89	    const swaggerUsers = swaggerSpec.paths['/users'] as Record<string, unknown> | undefined;
