293	/**
294	 * Safely evaluate a simple condition of the form "input.field op value".
295	 * Only supports comparison operators and field access — no arbitrary code execution.
296	 */
297	function safeEvaluateCondition(condition: string, input: Record<string, unknown>): boolean {
298	  // Parse "input.field op value" patterns only
299	  const match = condition.match(/^input\.(\w+)\s*(>=|<=|===|!==|>|<)\s*(.+)$/);
300	  if (!match) return false;
301	
302	  const [, field, op, rawValue] = match;
303	  const fieldValue = input[field];
304	
305	  // Parse the comparison value
306	  let compareValue: unknown;
307	  const trimmed = rawValue.trim();
308	  if (trimmed === 'true') compareValue = true;
309	  else if (trimmed === 'false') compareValue = false;
310	  else if (/^-?\d+(\.\d+)?$/.test(trimmed)) compareValue = Number(trimmed);
311	  else if (/^['"].*['"]$/.test(trimmed)) compareValue = trimmed.slice(1, -1);
312	  else return false;
313	
314	  switch (op) {
315	    case '>': return Number(fieldValue) > Number(compareValue);
316	    case '<': return Number(fieldValue) < Number(compareValue);
317	    case '>=': return Number(fieldValue) >= Number(compareValue);
318	    case '<=': return Number(fieldValue) <= Number(compareValue);
319	    case '===': return fieldValue === compareValue;
320	    case '!==': return fieldValue !== compareValue;
321	    default: return false;
322	  }
323	}
